INSERT INTO `defects` VALUES (1,'筛选条件全部重置为默认值，需要重新设置',NULL,2,NULL,'2026-06-14 08:45:58.183579','在用户管理列表页设置筛选条件后，切换Tab再返回，筛选条件被清空','Chrome 125 / Edge 125 / Firefox 127，Windows 11，React 19前端','返回用户管理页面后，之前设置的筛选条件保持不变',NULL,NULL,NULL,4,'用户管理列表页，设置部门+角色筛选条件，切换到其他Tab页后返回，之前设置的筛选条件全部丢失','P1',NULL,2,'1.进入用户管理页面\n2.设置部门=\'技术部\'，角色=\'工程师\'\n3.点击\'角色管理\'Tab\n4.点击\'用户管理\'Tab返回',NULL,3,'DRAFT','用户列表页筛选条件偶发重置','2026-06-14 08:45:58.183579',3,NULL,NULL,0,2,NULL,1,NULL),(2,'按钮被键盘完全遮挡，用户无法操作，只能收起键盘后才能点击',NULL,3,NULL,'2026-06-14 08:45:58.197606','在移动端浏览器中打开缺陷详情页，点击底部操作按钮时弹出的虚拟键盘遮挡了按钮区域','iOS 17 Safari / Android 14 Chrome，屏幕尺寸375×812及以下','弹出键盘后，确认/取消按钮自动上移到可见区域',NULL,NULL,NULL,5,'iOS Safari / Android Chrome，点击\'流转\'按钮时，弹出的确认表单中虚拟键盘遮挡了确认/取消按钮','P0',NULL,3,'1.用手机浏览器打开系统\n2.进入任意缺陷详情\n3.点击底部\'流转\'按钮\n4.在弹出的表单中点击输入框',NULL,4,'DRAFT','移动端H5页面底部按钮被虚拟键盘遮挡','2026-06-14 08:45:58.197606',4,NULL,NULL,0,1,NULL,1,NULL),(3,'列表无变化，手动刷新页面后才显示新状态',NULL,3,NULL,'2026-06-14 08:45:58.205204','对缺陷列表进行批量状态变更后，列表数据没有自动刷新，需手动F5刷新页面才能看到最新状态','生产环境 Chrome 125','列表自动刷新，被操作的3条缺陷状态更新为ANALYZED',NULL,NULL,NULL,2,'选中3条缺陷→点击批量操作→选择\'标记为已分析\'→确认→列表仍显示旧状态','P2',NULL,2,'1.在缺陷列表勾选3条状态为TRIAGING的缺陷\n2.点击批量操作按钮\n3.选择\'标记为已分析\'\n4.点击确认执行',NULL,3,'DRAFT','批量操作后列表未自动刷新','2026-06-14 08:45:58.205204',3,NULL,NULL,0,3,NULL,1,NULL),(4,'浏览器卡死约15秒后弹窗出现，期间无法进行任何操作',NULL,3,NULL,'2026-06-14 08:45:58.214860','点击附件缩略图预览大图时，浏览器CPU占用飙升至100%，页面无响应约15秒','Chrome 125 / Edge 125，Windows 11，内存16GB','弹窗在1-2秒内显示大图预览，可正常缩放和拖拽',NULL,NULL,NULL,3,'附件为8000×6000分辨率PNG截图，点击预览后浏览器卡死','P1',NULL,3,'1.上传一张高分辨率(8000×6000)PNG截图作为附件\n2.在缺陷详情页点击该附件缩略图\n3.等待预览弹窗出现',NULL,4,'DRAFT','附件预览大图时浏览器卡死','2026-06-14 08:45:58.214860',4,NULL,NULL,0,2,NULL,1,NULL),(5,'铃铛显示5条未读，通知中心内只有2条已读和1条未读',NULL,1,NULL,'2026-06-14 08:45:58.222534','顶部导航栏通知铃铛的未读数字显示5条，但点击进入通知中心后实际只有2条未读消息','全平台复现，Chrome 125 / Firefox 127，生产环境','铃铛未读数字与通知中心内未读消息数一致',NULL,NULL,NULL,2,'未读计数与通知中心内实际未读数不一致','P3',NULL,2,'1.等待接收多条通知\n2.查看顶栏铃铛显示的未读数\n3.点击铃铛进入通知中心\n4.对比未读消息数量',NULL,2,'DRAFT','通知中心未读计数与实际不符','2026-06-14