  `published_at` datetime(6) DEFAULT NULL,
  `status` enum('AUTO_GENERATED','PUBLISHED','REVIEWED') NOT NULL,
  `title` varchar(255) NOT NULL,
  `type` enum('REGRESSION_TEST','RISK_RULE','TROUBLESHOOTING') NOT NULL,
  `defect_id` bigint DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `FKtk9q7ynngtjg1e9f7mj9siwuo` (`defect_id`),
  CONSTRAINT `FKtk9q7ynngtjg1e9f7mj9siwuo` FOREIGN KEY (`defect_id`) REFERENCES `defects` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=91 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
